import { ChatFlow } from 'flowise/dist';

const detectTokenBloat = (chatflow: ChatFlow, executionData: any) => {
  const nodeOutputs = chatflow.nodes.map(node => executionData[node.id]?.output);
  const totalTokens = nodeOutputs.reduce((sum, output) => sum + (output?.tokenCount || 0), 0);
  const intermediateTokens = nodeOutputs.slice(0, -1).reduce((sum, output) => sum + (output?.tokenCount || 0), 0);

  return {
    isBloated: intermediateTokens / totalTokens > 0.7,
    bloatRatio: intermediateTokens / totalTokens,
    wastefulNodes: nodeOutputs.slice(0, -1).map((o, i) => ({ nodeId: chatflow.nodes[i].id, tokens: o.tokenCount }))
  };
};

const scanRetrievalRelevance = (retrieverNode: any, docs: any[]) => {
  const avgSimilarity = docs.reduce((sum, doc) => sum + (doc.metadata?.similarity || 0), 0) / docs.length;
  const lowRelevanceDocs = docs.filter(doc => (doc.metadata?.similarity || 0) < 0.75);

  return {
    avgSimilarity,
    lowRelevanceCount: lowRelevanceDocs.length,
    shouldOptimize: avgSimilarity < 0.75 || lowRelevanceDocs.length > 3,
    problematicDocs: lowRelevanceDocs
  };
};

const detectContextLoss = (agentOutputs: any[], handoffData: any) => {
  const handoffTokens = handoffData.summaryTokenCount || 0;
  const fullContextTokens = agentOutputs.reduce((sum, output) => sum + output.tokenCount, 0);

  return {
    contextLossRatio: handoffTokens / fullContextTokens,
    hasLoss: handoffTokens > fullContextTokens * 0.5,
    recommendation: handoffTokens > fullContextTokens * 0.5 ? 'Add summarization node' : 'OK'
  };
};

