const truncateOutput = (input: string, maxTokens: number = 512): string => {
  const encoder = new TextEncoder();
  const tokenCount = encoder.encode(input).length;

  if (tokenCount <= maxTokens) return input;

  // Rough token estimation for truncation
  const charPerToken = 4;
  const maxChars = maxTokens * charPerToken;
  return input.slice(0, maxChars) + '... [truncated]';
};

