import { Vex } from '@vex_dev/sdk';
import { ChatFlow, FlowiseRunner } from 'flowise/dist';

const vex = new Vex({
  projectId: 'your-project-id',
  apiKey: process.env.VEX_API_KEY
});

// Add Vex callback to Flowise chatflow
const optimizedChatflow: ChatFlow = {
  ...yourChatflow,
  callbacks: {
    onNodeExecute: async (nodeId: string, input: any, output: any) => {
      await vex.track({
        event: 'node_execution',
        data: {
          nodeId,
          inputTokens: input.tokenCount,
          outputTokens: output.tokenCount,
          nodeType: yourChatflow.nodes.find(n => n.id === nodeId)?.type
        }
      });
    },
    onCostAnomaly: async (alert: any) => {
      // Auto-deploy fix
      const fixConfig = generateOptimizationFix(alert);
      await updateChatflow(fixConfig);
    }
  }
};

const runner = new FlowiseRunner();
await runner.runChatflow(optimizedChatflow);
